const initTracker = (scope) => {
  const o={};
  TRACKER_TASKS.forEach(t=>{
    if(t.auto) { o[t.id]={status:"",dates:{},assignee:""}; return; }
    if(scope && t.scopeKey && scope[t.scopeKey]) { o[t.id]={status:"",dates:{},assignee:""}; }
  });
  return o;
};

