// ── Utility ───────────────────────────────────────
const fmt = n => `£${Number(n||0).toLocaleString()}`;
const todayStr = new Date().toISOString().slice(0,10);
const daysUntil = d => { if(!d||d==="Exempt") return 999; return Math.ceil((new Date(d)-new Date())/(864e5)); };
const uid = () => `id-${Date.now()}-${Math.random().toString(36).slice(2,6)}`;
const contrastText = (hex) => { const h=hex.replace("#","");const r=parseInt(h.substr(0,2),16);const g=parseInt(h.substr(2,2),16);const b=parseInt(h.substr(4,2),16);return(r*299+g*587+b*114)/1000>150?"#0B1120":"#ffffff"; };

// ── Shared UI Components ──────────────────────────
const Badge = ({label,color}) => <span style={{background:color+"18",color,padding:"3px 10px",borderRadius:4,fontSize:11,fontWeight:600,letterSpacing:"0.3px",textTransform:"uppercase",whiteSpace:"nowrap"}}>{label}</span>;
const StatusBadge = ({label,color}) => <span style={{background:color,color:contrastText(color),padding:"3px 10px",borderRadius:4,fontSize:11,fontWeight:600,letterSpacing:"0.3px",textTransform:"uppercase",whiteSpace:"nowrap"}}>{label}</span>;
const Dot = ({color}) => <span style={{width:8,height:8,borderRadius:"50%",background:color,boxShadow:`0 0 6px ${color}`,display:"inline-block",flexShrink:0}} />;

const Btn = ({children,onClick,primary,danger,small,c,disabled,style:sx={}}) => (
  <button onClick={onClick} disabled={disabled} style={{padding:small?"6px 14px":"10px 22px",background:danger?c.red:primary?`linear-gradient(135deg,${c.amber},${c.amberDark})`:c.surface,border:primary||danger?"none":`1px solid ${c.border}`,borderRadius:6,color:primary||danger?"#fff":c.textMuted,fontSize:small?12:13,fontWeight:600,cursor:disabled?"not-allowed":"pointer",opacity:disabled?0.5:1,fontFamily:"'DM Sans',sans-serif",...sx}}>{children}</button>
);

const Card = ({c,children,style:sx={},onClick}) => <div onClick={onClick} style={{background:c.surface,border:`1px solid ${c.border}`,borderRadius:8,padding:22,...sx}}>{children}</div>;

const Stat = ({label,value,sub,accent,c}) => (
  <div style={{background:c.surface,border:`1px solid ${accent?c.amber+"50":c.border}`,borderRadius:8,padding:"16px 18px",position:"relative",overflow:"hidden"}}>
    {accent && <div style={{position:"absolute",top:0,left:0,right:0,height:2,background:`linear-gradient(90deg,${c.amber},${c.amberDark})`}} />}
    <div style={{fontSize:11,color:c.textMuted,textTransform:"uppercase",letterSpacing:"0.8px",marginBottom:5}}>{label}</div>
    <div style={{fontSize:24,fontWeight:700,color:accent?c.amber:c.text,fontFamily:"'Space Mono',monospace",letterSpacing:"-1px"}}>{value}</div>
    {sub && <div style={{fontSize:11,color:c.textDim,marginTop:3}}>{sub}</div>}
  </div>
);

const Field = ({label,value,onChange,type="text",placeholder,c,options,textarea,style:sx={}}) => (
  <div style={{marginBottom:12,...sx}}>
    {label && <label style={{fontSize:11,color:c.textMuted,display:"block",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.5px",fontWeight:600}}>{label}</label>}
    {options ? (
      <select value={value} onChange={e=>onChange(e.target.value)} style={{width:"100%",padding:"9px 12px",background:c.inputBg,border:`1px solid ${c.border}`,borderRadius:6,color:c.text,fontSize:13,fontFamily:"'DM Sans',sans-serif",outline:"none"}}>{options.map(o=><option key={typeof o==="string"?o:o.v} value={typeof o==="string"?o:o.v}>{typeof o==="string"?o:o.l}</option>)}</select>
    ) : textarea ? (
      <textarea value={value} onChange={e=>onChange(e.target.value)} rows={3} placeholder={placeholder} style={{width:"100%",padding:"9px 12px",background:c.inputBg,border:`1px solid ${c.border}`,borderRadius:6,color:c.text,fontSize:13,fontFamily:"'DM Sans',sans-serif",outline:"none",resize:"vertical",boxSizing:"border-box"}} />
    ) : (
      <input type={type} value={value} onChange={e=>onChange(type==="number"?Number(e.target.value):e.target.value)} placeholder={placeholder} style={{width:"100%",padding:"9px 12px",background:c.inputBg,border:`1px solid ${c.border}`,borderRadius:6,color:c.text,fontSize:type==="number"?15:13,fontFamily:type==="number"?"'Space Mono',monospace":"'DM Sans',sans-serif",fontWeight:type==="number"?700:400,outline:"none",boxSizing:"border-box"}} />
    )}
  </div>
);

// ── People Picker (searchable dropdown + free text) ──
const PeoplePicker = ({label,value,onChange,c,co,placeholder="Search or type name..."}) => {
  const [q,setQ] = React.useState("");
  const [open,setOpen] = React.useState(false);
  const allPeople = [
    ...((co.subcontractors||[]).map(s=>({name:s.name||s.companyName,group:"Subcontractors",sub:s.trade}))),
    ...((co.operatives||[]).map(o=>({name:o.name,group:"Direct Labour",sub:o.trade}))),
    ...((co.users||[]).map(u=>({name:u.name,group:"Users",sub:u.role}))),
    {name:"Shared",group:"Other",sub:""},{name:"Unassigned",group:"Other",sub:""},{name:"Site Pool",group:"Other",sub:""},{name:"Store",group:"Other",sub:""},
  ];
  const filtered = q ? allPeople.filter(p=>p.name.toLowerCase().includes(q.toLowerCase())) : allPeople;
  const groups = {};
  filtered.forEach(p=>{if(!groups[p.group])groups[p.group]=[];groups[p.group].push(p);});
  return (
    <div style={{marginBottom:12,position:"relative"}}>
      {label && <label style={{fontSize:11,color:c.textMuted,display:"block",marginBottom:5,textTransform:"uppercase",letterSpacing:"0.5px",fontWeight:600}}>{label}</label>}
      <input type="text" value={open?q:value||""} 
        onFocus={()=>{setOpen(true);setQ("");}}
        onChange={e=>{setQ(e.target.value);onChange(e.target.value);if(!open)setOpen(true);}}
        onBlur={()=>setTimeout(()=>setOpen(false),200)}
        placeholder={placeholder}
        style={{width:"100%",padding:"9px 12px",background:c.inputBg,border:`1px solid ${open?c.amber:c.border}`,borderRadius:6,color:c.text,fontSize:13,fontFamily:"'DM Sans',sans-serif",outline:"none",boxSizing:"border-box"}}/>
      {open && filtered.length>0 && (
        <div style={{position:"absolute",top:"100%",left:0,right:0,zIndex:50,maxHeight:220,overflowY:"auto",background:c.surface,border:`1px solid ${c.border}`,borderRadius:6,boxShadow:"0 8px 24px rgba(0,0,0,0.3)",marginTop:2}}>
          {Object.entries(groups).map(([grp,people])=>(
            <div key={grp}>
              <div style={{padding:"4px 10px",fontSize:9,color:c.amber,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.5px",background:c.surfaceAlt,borderBottom:`1px solid ${c.border}`}}>{grp}</div>
              {people.map(p=>(
                <div key={p.name+p.group} onMouseDown={e=>{e.preventDefault();onChange(p.name);setQ("");setOpen(false);}}
                  style={{padding:"6px 12px",fontSize:12,cursor:"pointer",display:"flex",justifyContent:"space-between",alignItems:"center",borderBottom:`1px solid ${c.border}15`}}
                  onMouseEnter={e=>e.currentTarget.style.background=c.amberGlow}
                  onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                  <span style={{fontWeight:600}}>{p.name}</span>
                  {p.sub&&<span style={{fontSize:10,color:c.textDim}}>{p.sub}</span>}
                </div>
              ))}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

