                  {t.status==="active"&&<Btn small c={c} onClick={()=>{if(window.confirm("Suspend "+t.companyName+"?"))updateCo(co=>({...co,platformTenants:(co.platformTenants||[]).map(x=>x.id===t.id?{...x,status:"suspended"}:x)}));}}>{"Suspend"}</Btn>}
