                  <tbody>{[["Projects","1","5","Unlimited"],["Users","5","15","Unlimited"],["Properties","20","100","Unlimited"],["Invoicing","✓","✓","✓"],["Compliance","Basic","Full","Full + AI"],["Site Inspections","✓","✓","✓"],["Letters & Letterheads","✓","✓","Custom branding"],["Client Portal","—","✓","✓"],["Supplier Evaluations","—","✓","✓"],["API Access","—","✓","✓"],["White Label","—","—","✓"],["Priority Support","—","—","✓"],["Onboarding Call","—","30 min","2 hours"]].map((row,i)=><tr key={i} style={{borderBottom:"1px solid "+c.border+"30"}}>{row.map((cell,j)=><td key={j} style={{padding:"6px",textAlign:j>0?"center":"left",color:cell==="—"?c.textDim+"80":cell==="✓"?c.green:c.text}}>{cell}</td>)}</tr>)}</tbody>
