                  <div style={{flex:1,height:20,background:c.border+"30",borderRadius:4,overflow:"hidden"}}><div style={{height:20,background:p.color+"40",borderRadius:4,width:mrr>0?String(Math.round(planMrr/mrr*100))+"%":"0%"}}><span style={{fontSize:9,fontWeight:700,color:p.color,padding:"2px 6px"}}>{planTenants.length+" tenants"}</span></div></div>
