                  if(!modalForm.name) return;
                  updateCo(co=>({...co,subcontractors:[...co.subcontractors,{...modalForm,id:uid(),position:modalForm.trade||"",amountOwed:0,photoUrl:"",dob:"",nino:modalForm.nino||"",cscs:"",cscsExpiry:modalForm.cscsExpiry||"",insuranceExpiry:modalForm.insuranceExpiry||"",asbestosExpiry:modalForm.asbestosExpiry||"",bankAccName:modalForm.bankAccName||"",bankName:modalForm.bankName||"",bankSortCode:modalForm.bankSortCode||"",bankAccNumber:modalForm.bankAccNumber||"",altPhone:"",asbestosCert:modalForm.asbestosExpiry||"",drivingLicence:"",otherLicence:"",contactName:modalForm.contactName||"",companyReg:modalForm.companyReg||"",createdDate:new Date().toISOString().slice(0,10)}]}));
