                <div><label style={{fontSize:11,color:c.textDim}}>Assign To</label><select value={modalForm.assignee||""} onChange={e=>setModalForm(f=>({...f,assignee:e.target.value}))} style={{width:"100%",padding:6,borderRadius:6,background:c.bg,border:`1px solid ${c.border}`,color:c.text,fontSize:12}}><option value="">Unassigned</option>{[...co.operatives,...co.subcontractors].filter(w=>w.active!==false).map(w=><option key={w.id} value={w.name}>{w.name}</option>)}</select></div>
