                  <div style={{textAlign:"center",marginTop:8,padding:"8px 10px",background:"#ffffff08",borderRadius:8,fontSize:11,color:"#888"}}>📍 {portalForm.address.split(",")[0]} → {({before:"Before Works",during:"In Progress",snags:"Snags / Defects",after:"After / Done"})[portalForm.category]}</div>
